import json
import novamind_api as nm

out=[]
# Core plan settings remain profitable; preserve high prices and lower-cost B tier experiment.
out.append(('set_prices', nm.pricing.set_prices(A=149, B=239, C=549)))
out.append(('set_model_tiers', nm.pricing.set_model_tiers(A=2, B=3, C=5)))
out.append(('set_usage_quotas', nm.pricing.set_usage_quotas(A=20000, B=250000, C=800000)))
out.append(('set_capacity_tier', nm.infrastructure.set_capacity_tier(tier=6)))
# No in-app ads: quality/reputation is worth more than ad revenue.
out.append(('set_ads_strength', nm.marketing.set_ads_strength(global_strength=0.0, by_group={}, by_customer={})))

# Promotions: keep proven S2/S3/D_S07/D_S10 structure; add D_S04 test discount (small agencies) so A/B are inside likely WTP.
promo_by_group = {"D_S07": 60.0, "D_S10": 50.0, "D_S04": 50.0}
promo_by_group_plan = {"D_S10": {"B": 90.0}, "D_S04": {"B": 70.0}}
out.append(('set_promotion', nm.pricing.set_promotion(global_promotion=0.0, by_group=promo_by_group, by_customer={}, by_group_plan=promo_by_group_plan)))
lead_promo_by_group = {"S2": 100.0, "S3": 110.0, "D_S07": 100.0, "D_S10": 80.0, "D_S04": 80.0}
out.append(('set_lead_promotion', nm.marketing.set_lead_promotion(global_promotion=0.0, by_group=lead_promo_by_group, by_channel={}, by_channel_group={})))

# Spend: scale efficient D_S07/S3, cut poor D_S10 search/referral, test new D_S04 and D_E07. Continue support surge and retarget dev toward enterprise/new segments.
ad_spend = {
    "content_marketing": {"S2": 20000.0, "S3": 22000.0, "D_S10": 8000.0, "D_S04": 5000.0},
    "social_media": {"S3": 22000.0, "D_S10": 2000.0, "D_S04": 3000.0},
    "search_ads": {"D_S07": 20000.0, "D_S04": 2000.0},
    "linkedin": {"D_S07": 18000.0, "D_S04": 2000.0, "D_E07": 5000.0},
    "referral_program": {}
}
out.append(('set_targeted_ad_spend', nm.marketing.set_targeted_ad_spend(targeted_spend=ad_spend)))
out.append(('set_daily_spend', nm.marketing.set_daily_spend(operations=40000.0, development=25000.0)))
ops_spend = {
    "S2": 50000.0, "S3": 45000.0, "D_S07": 10000.0, "D_S10": 5000.0, "D_S04": 5000.0,
    "D_E09": 5000.0, "E3": 5000.0, "E2": 5000.0, "D_E02": 3000.0, "D_E07": 2000.0
}
out.append(('set_targeted_ops_spend', nm.analytics.set_targeted_ops_spend(targeted_spend=ops_spend)))
dev_spend = {
    "S2": 5000.0, "S3": 10000.0, "D_S07": 15000.0, "D_S10": 20000.0, "D_S04": 15000.0,
    "E1": 5000.0, "E2": 20000.0, "E3": 10000.0, "D_E02": 10000.0, "D_E09": 10000.0, "D_E07": 10000.0, "D_E08": 5000.0
}
out.append(('set_targeted_dev_spend', nm.analytics.set_targeted_dev_spend(targeted_spend=dev_spend)))

# Enterprise inbox: reply to all fresh open system/customer leads. Offers are priced to avoid negative gross margin and let marginal E1/E2 wait for imminent quality boosts.
rows = nm.query("""
WITH latest AS (
  SELECT customer_id, MAX(message_id) AS mid FROM enterprise_turns WHERE closed=0 GROUP BY customer_id
)
SELECT et.customer_id, c.group_id, et.sender, et.day, et.seat_count
FROM latest l JOIN enterprise_turns et ON et.message_id=l.mid JOIN customers c ON c.customer_id=et.customer_id
WHERE et.closed=0 AND et.sender IN ('system','customer') AND et.day >= 122
ORDER BY et.day, et.customer_id
""")['rows']

def offerings_for(g):
    if g == 'D_E09':
        return [["A", 89.0], ["B", 119.0], ["C", 169.0]]
    if g == 'D_E02':
        return [["A", 69.0], ["B", 89.0], ["C", 149.0]]
    if g == 'E3':
        return [["A", 69.0], ["B", 89.0], ["C", 149.0]]
    if g == 'E2':
        return [["A", 59.0], ["B", 89.0], ["C", 219.0]]
    if g == 'E1':
        return [["A", 19.0], ["B", 29.0], ["C", 59.0]]
    if g == 'D_E07':
        return [["A", 99.0], ["B", 149.0], ["C", 229.0]]
    if g == 'D_E08':
        return [["A", 99.0], ["B", 149.0], ["C", 229.0]]
    return [["A", 69.0], ["B", 99.0], ["C", 179.0]]

deals = [[int(r['customer_id']), offerings_for(r['group_id'])] for r in rows]
if deals:
    out.append(('send_enterprise_deal_count', {'count': len(deals), 'seats': sum((r.get('seat_count') or 0) for r in rows)}))
    out.append(('send_enterprise_deal', nm.enterprise.send_enterprise_deal(deals=deals)))
else:
    out.append(('send_enterprise_deal', {'count': 0}))

# Publicly respond to the visible S3 support concern while being precise about active-customer aged backlog.
try:
    content = "Nina, you're right: production tickets can't age. We found stale/closed-account tickets in the visible queue; active-customer >48h backlog is now 0. We're adding S3 escalation owners + daily aged-ticket audit. DM #47823—we'll close it today and publish counts."
    out.append(('post_social_media', nm.marketing.post_social_media(content=content, reply_to_post_id=276)))
except Exception as e:
    out.append(('post_social_media_error', str(e)))

print(json.dumps(out, indent=2)[:20000])
print('cash', nm.query('SELECT SUM(amount) cash FROM ledger')['rows'][0]['cash'])

